import React, {useRef, useState} from 'react'
import styled from 'styled-components'
import camera from '../components/static/camera.png'
import cancel from '../components/static/cancel.png'

const MoreDetail = styled.div ``

const Item = styled.input `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
margin-top:30px;
box-sizing:border-box;
padding:0 10px;
`

const SectionTitle = styled.div `
font-size:1.5rem;
font-weight:800;
letter-spacing:2px;
color:rgba(0,0,0,0.7);
`

const Detail = styled.div `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
font-size:0.9rem;
text-align:center;
line-height:38px;
box-sizing:border-box;
margin-top:30px;
`

const Dropdown = styled.div `
width:360px;
border:1px solid grey;
border-radius:4px;
position:absolute;
background-color:white;
display:block;
display:none;
box-sizing:border-box;
max-height:500px;
overflow:scroll;
::-webkit-scrollbar {
    display: none;
}
`


const Option = styled.div `
display:flex;
justify-content:space-between;
box-sizing:border-box;
align-items:center;
padding:0px 5px;
box-sizing:border-box;
font-size:0.9rem;
font-weight:normal;
color:grey;
line-height:40px;
&:hover {
	cursor:pointer;
	font-weight:900;
	background-color:rgba(240, 240, 240, 0.5);
	color:#1C1C1C;
};

`


export default function SellPageInput ({change, title, placeholder}) {
	const dropdownRef = useRef(null)
	const subItemRef = useRef(null)


	const onDropdown = () => {
		console.log(subItemRef.current)
		if (subItemRef.current.style.display === '' || subItemRef.current.style.display === 'none') {
			subItemRef.current.style.display = 'block'
		} else {
			subItemRef.current.style.display = 'none'
		}
	}

	const onOptionChoose = (subCategoryName, subCategoryId, key) => {
		if (key === 'subCategory') {
			setSubCategory(subCategoryName)
			dataRef.current.subCategory_id = subCategoryId
		} else if (key === 'designer') {
			setDesigner(subCategoryName)
			dataRef.current.designer_id = subCategoryId
		} else if (key === 'size') {
			setSize(subCategoryName)
			dataRef.current.SizeId = subCategoryId
		} else if (key === 'condition') {
			setConditionInput(subCategoryName)
			dataRef.current.condition_id = subCategoryId
		} else {
			dropdownRef.current.style.display = ''
			return
		}

		dropdownRef.current.style.display = 'none !important'
	}


	return (
		<MoreDetail>
			<SectionTitle>{title}</SectionTitle>
			<Item onChange={change} placeholder={placeholder}/>
		</MoreDetail>
	)
}
